VALUES
  ('social-worker-moex-02911', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '相較於社會工作督導，下列對於社會工作諮詢的敘述何者錯誤？', '["諮詢涉及的問題較督導為廣泛", "諮詢涉入組織的時間較長", "諮詢對於工作結果沒有行政上的權威或責任", "諮詢者與受諮詢者之間的關係通常是自願和同等地位的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02912', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '規劃（planning）是社會福利組織非常重要的工作項目，它是一種預設目標的過程，最終將設計出一個可 以達到目標的計畫。根據Weinbach（2003）的分類，以下何者屬於根據組織與環境的關係，強調根本性、 大方向、長期性規劃、未來導向的規劃類型？', '["權變性規劃（contingency planning）", "策略性規劃（strategic planning）", "作業性規劃（operational planning）", "長期性規劃（long-range planning）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02913', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作實務最關心的理應是社工員的處遇對案主造成什麼改變（change）。從方案績效評估的角度來看， 若著重於案主的改變，在評估時應更注重方案的：', '["效率（efficiency）", "成效（effectiveness）", "經濟（economy）", "外部性（externality）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02914', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '企業組織通常透過組織層級進行作業控制、財務控制、結構控制及策略控制，這些控制某種程度也適用 於社會服務組織，績效管理（performance management）即是控制過程的主軸，攸關社會服務目標的達成 至為重要。請問下列何者對「績效管理」的描述正確？', '["績效評估即是績效管理，評估績效即能達到績效管理的目標", "績效管理是一種迫使員工提升效率的手段，表格的填寫是必要的過程", "績效管理有利於提供發放績效獎金及秋後算帳的客觀依據", "績效管理是將組織的目標緊扣著組織的「人」（管理者和員工）與「事」（方案和組織）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02915', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者符合管理學大師Peter F. Drucker（1955）所提出對於目標管理（management by objective, MBO）的 描述？', '["委託管理顧問公司之有效規劃和目標設定", "管理者和部屬設定與組織目標相關的個別目標", "在發展和選擇達成目標上必須有一致性的規範", "檢視最後階段成效與目標相關的績效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02916', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '預算具有控制、管理、規劃三大目的。在預算系統中以控制為主要目的是那一種預算系統？', '["單項預算系統（line-item budgeting）", "功能預算系統（functional budgeting）", "方案預算系統（program budgeting）", "績效預算系統（performance budgeting）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02917', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '規劃服務方案時，在服務策略上特別採用外展服務的方法是為了想提升那一項服務品質？', '["保證性", "可靠性", "可近性", "安全性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02918', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '針對一個創新的方案，評估者關心的議題有：需求評定是否掌握服務對象的需求、方案所執行的措施是 否符合方案規劃的內容、方案的參與者是否為事先規劃的服務對象、方案經費是否運用得當等。根據這 些所關心的議題，此時評估者最需要做的評估是那一種？', '["過程評估", "總結性評估", "成本效益評估", "品質評估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02919', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利機構在做年度的方案評估，特別是運用量化測量工具來做評估時，其最主要的是要評估方案的 什麼項目是否達成或達成的程度？', '["願景（vision）", "方案的抽象目的（goals）", "方案的具體目標（objectives）", "理論假設"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02920', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案評估時，我們經常評估工作人員的服務態度是否親切、有禮貌，這個評估指標可稱為保證性 （assurance）。請問保證性是屬於那一個績效面向的評估指標？', '["效率（efficiency）", "品質（quality）", "成效（effectiveness）", "成本效益（cost-benefit）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02921', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '總結評估（summative evaluation）通常是針對已經完成之社會服務方案進行評估，據以研判方案的優缺點， 進行方案之延續或選擇，由於需要客觀的第三者進行，因此由外部評估較為適宜。請問「總結評估」應 該包含那些評估在內較完整？', '["結果評估（evaluation of outcome）與適切性評估（evaluation of adequacy）", "結果評估（evaluation of outcome）與成效評估（evaluation of effectiveness）", "適切性評估（evaluation of adequacy）與成效評估（evaluation of effectiveness）", "結果評估（evaluation of outcome）、適切性評估（evaluation of adequacy）及成效評估（evaluation of effectiveness）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02922', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Martin（2002）對於方案的生命週期模式的描述何者正確？', '["界定(cid:198)執行(cid:198)規劃(cid:198)結束(cid:198)評估", "界定(cid:198)規劃(cid:198)執行(cid:198)結束(cid:198)評估", "界定(cid:198)執行(cid:198)規劃(cid:198)評估(cid:198)結束", "界定(cid:198)規劃(cid:198)執行(cid:198)評估(cid:198)結束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02923', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一財團法人社會福利基金會聘用專職工作人員約 100 人，而大部分的專職員工是社會工作員。請問下 列那項工作不是該基金會董（監）事的主要職責？', '["修改捐助章程", "審查年度預算", "維繫基金會的使命", "督導社會工作實務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02924', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '臺中市某家醫院的志工已經有多名志工服務年資滿三年，且服務時數均超過 300 小時。請問該醫院的志 願服務業務承辦人得檢具相關文件向那一個機關為這些志工申請志願服務榮譽卡？', '["內政部社會司", "行政院衛生署", "臺中市政府衛生局", "臺中市政府社會局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02925', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據我國於民國95年通過的〈公益勸募條例〉，下列募款活動的描述中那一項符合〈公益勸募條例〉的 規定？', '["我國的任何公立或民間組織都可以從事募款活動", "辦理募款活動之前只要向主管機關報備即可", "辦理募款活動的期間最長為三個月", "勸募活動所得在新臺幣一千萬元以下者，辦理募款活動的必要支出為募款所得的百分之十五以內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02926', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列那一項活動是社會福利機構的社會行銷（social marketing）活動？', '["中秋節月餅義賣", "人口販運防制理念的宣導", "散發介紹機構宗旨與服務內容的機構簡介", "籌措方案經費的募款活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02927', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據中華民國建國一百年社會福利政策綱領所宣示，下列何者不是「新社會」的核心價值？', '["自由", "公平", "正義", "包容"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02928', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關女性主義理論對福利與公民權的主張，下列何者正確？', '["貧窮女性化的現象已然消失，主要原因是多數女性已能在就業市場中賺取薪資，取得獨立的社會保障 資格", "女性應該擁有獨立的公民權與社會權，不應被視為男性的依賴者，故養家薪資（family wage）是一種 父權的表現", "兩性的公民權與社會權內涵應該儘可能都一致，才是平等與正義的象徵", "女性主義學者認為福利國家應強化雙軌式系統設計，以提升對女性的經濟保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02929', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '目前內政部正在推動平民銀行實驗計畫，是透過鼓勵儲蓄、參與志願服務、參與教育訓練等策略來協助 經濟弱勢族群脫離貧窮。請問這是那種脫貧策略？', '["急難救助", "資產形成", "工作福利", "財稅福利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02930', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會政策與意識形態的敘述，下列何者錯誤？', '["新右派福利意識形態主要的政治體現是民營化，以1980年代的雷根主義與柴契爾主義為代表", "第三條路的意識形態主張為因應全球化風險，福利應該以社會投資為導向，強化依賴者的就業動機", "老左派的社會民主意識形態，在全球化的挑戰下，紛紛開始福利改革，向第三條路靠攏", "新右派與第三條路有許多共同特質，包括強調個人責任、國家效率、充分就業與結果平等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02931', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '主張「開放讓影響力被認可的利益團體參與決策制定，促進國家與政治結盟團體的協商」，是那一種解 釋社會政策制定過程的觀點？', '["菁英論", "社會統合論", "階級動員論", "多元論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02932', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '第三條路福利意識型態是影響當前福利國家的重要思潮。有關第三條路的敘述，下列何者正確？', '["在政策實施上以英美1980年代福利縮減為代表", "關注全球化現象對傳統福利國家的挑戰，認同資本主義市場運作邏輯", "主張政府應扮演大量投資社會公共建設的角色", "強調個人的工作責任，強化男性養家責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02933', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在晚近的福利國家改革中，福利混合經濟一直是福利輸送系統設計的核心概念。下列有關福利混合經濟 的敘述，何者錯誤？', '["此概念係立基於福利多元主義與新右派的價值", "重視政府部門與志願部門的夥伴關係", "家庭此一非正式部門正面臨萎縮，所以不適合納入福利混合體系", "鼓勵商業部門積極投入福利供給與輸送"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02934', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '女性主義對於福利國家的制度提出許多批判，但不同的女性主義流派對於福利國家有不同的看法，認為 福利國家可以在法制上做修改，而消除女性在參與公共及社會機會的阻礙，此女性主義派別為：', '["基進主義女性主義", "社會主義女性主義", "自由主義女性主義", "後現代主義女性主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02935', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於普及性與選擇性福利的論述，下列何者正確？', '["普及性福利的行政成本較選擇性福利高", "我國內政部所推動的育兒津貼為一項普及性福利", "普及性福利的垂直再分配效果較選擇性福利高", "普及性福利強調公民權利的正當性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
